// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ProxyUser) predicate.ProxyUser {
	return predicate.ProxyUser(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ProxyUser) predicate.ProxyUser {
	return predicate.ProxyUser(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ProxyUser) predicate.ProxyUser {
	return predicate.ProxyUser(sql.NotPredicates(p))
}
